foreach ($screen in $screens) {
    $cleanTitle = $screen.title -replace ' ', '_'
    $imgFile = "$cleanTitle.png"
    $htmlFile = "$cleanTitle.html"
    
    Write-Host "Downloading $cleanTitle..."
    curl.exe -s -L -o $imgFile $screen.imgUrl
    curl.exe -s -L -o $htmlFile $screen.htmlUrl
}
Write-Host "Done!"
